framework_css:
:root {
  /* Color system */
  --color-primary-light: #ffffff;
  --color-primary-dark: #111111;

  --color-secondary-bg: #f5f5f5;
  --color-secondary-warm: #c59a84; /* warm beige from hero/article */

  --color-accent-rose: #c9898a; /* soft rose accent (e.g., special nav item) */

  --color-neutral-0: #ffffff;
  --color-neutral-50: #f2f2f2;
  --color-neutral-800: #333333;

  --color-success: #4caf50;
  --color-error: #e53935;
  --color-warning: #ffb300;
  --color-info: #1e88e5;

  /* Typography */
  --font-heading: 'Space Grotesk', 'Helvetica', sans-serif;
  --font-body: 'Source Sans 3', 'Arial', sans-serif;

  --font-size-h1: 2.6rem; /* ~42px on base 16 */
  --font-size-h2: 2rem;   /* ~32px */
  --font-size-h3: 1.5rem; /* ~24px */
  --font-size-body: 1rem; /* 16px */
  --font-size-small: 0.85rem; /* ~13-14px */

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  /* Spacing (8px scale) */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  /* Layout */
  --max-width: 1120px;
}

* {
  box-sizing: border-box;
}

html {
  font-size: 16px;
}

body {
  margin: 0;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-primary-dark);
  background-color: var(--color-neutral-0);
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover,
 a:focus {
  text-decoration: underline;
}

.container {
  max-width: var(--max-width);
  margin-left: auto;
  margin-right: auto;
  padding-left: var(--space-4);
  padding-right: var(--space-4);
}

/* Header & hero */

.site-header {
  background-color: var(--color-neutral-0);
  color: var(--color-neutral-0);
}

.hero {
  position: relative;
  background-color: var(--color-secondary-warm);
  /* Replace the gradient/image below with an actual family photo for production */
  background-image:
    linear-gradient(to bottom, rgba(0, 0, 0, 0.35), rgba(0, 0, 0, 0.45));
  /* A placeholder background color sits under the overlay */
  background-size: cover;
  background-position: center center;
}

.hero-inner {
  text-align: center;
  padding-top: var(--space-6);
  padding-bottom: var(--space-6);
}

.site-title {
  margin: 0 0 var(--space-2);
  font-family: var(--font-heading);
  font-size: var(--font-size-h1);
  font-weight: var(--font-weight-bold);
  letter-spacing: 0.12em;
  text-transform: uppercase;
  line-height: var(--line-height-tight);
  color: var(--color-neutral-0);
}

.site-tagline {
  margin: 0;
  font-size: 0.95rem;
  font-weight: var(--font-weight-regular);
  color: rgba(255, 255, 255, 0.9);
}

/* Primary navigation */

.primary-nav {
  background-color: var(--color-neutral-0);
  border-bottom: 1px solid var(--color-neutral-50);
}

.nav-list {
  list-style: none;
  margin: 0;
  padding-top: var(--space-3);
  padding-bottom: var(--space-3);

  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  column-gap: var(--space-5);
  row-gap: var(--space-2);
}

.nav-item {
  font-size: 0.97rem;
  font-weight: var(--font-weight-medium);
}

.nav-item a {
  position: relative;
  color: var(--color-primary-dark);
  padding-bottom: 2px;
}

.nav-item a:hover,
.nav-item a:focus {
  text-decoration: none;
}

.nav-item a::after {
  content: '';
  position: absolute;
  left: 0;
  bottom: 0;
  width: 0;
  height: 2px;
  background-color: var(--color-primary-dark);
  transition: width 160ms ease-out;
}

.nav-item a:hover::after,
.nav-item a:focus::after {
  width: 100%;
}

/* Optional class for highlighting a special section if desired */
.nav-item--accent a {
  color: var(--color-accent-rose);
}

/* Main content wrapper */

.site-main {
  background-color: var(--color-neutral-0);
  padding-top: var(--space-6);
  padding-bottom: var(--space-6);
}

/* Footer */

.site-footer {
  border-top: 1px solid var(--color-neutral-50);
  background-color: var(--color-neutral-0);
  padding-top: var(--space-5);
  padding-bottom: var(--space-5);
}

.footer-inner {
  text-align: center;
}

.footer-nav {
  margin-bottom: var(--space-3);
}

.footer-links {
  list-style: none;
  padding: 0;
  margin: 0 0 var(--space-2);

  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  column-gap: var(--space-4);
  row-gap: var(--space-2);
}

.footer-item {
  font-size: var(--font-size-small);
  font-weight: var(--font-weight-regular);
}

.footer-item a {
  color: var(--color-neutral-800);
}

.footer-item a:hover,
.footer-item a:focus {
  color: var(--color-primary-dark);
}

.footer-meta {
  margin: 0;
  font-size: var(--font-size-small);
  color: #777777;
}

/* Responsive adjustments */

@media (max-width: 768px) {
  .hero-inner {
    padding-top: var(--space-5);
    padding-bottom: var(--space-5);
  }

  .site-title {
    font-size: 2rem; /* ~32px */
    letter-spacing: 0.1em;
  }

  .site-tagline {
    font-size: 0.9rem;
  }

  .nav-list {
    column-gap: var(--space-3);
  }
}

@media (max-width: 480px) {
  .site-title {
    font-size: 1.75rem; /* ~28px */
  }

  .container {
    padding-left: var(--space-3);
    padding-right: var(--space-3);
  }
}
